#!/usr/bin/env python3
"""Apply ShadowCI v2.0.0 upgrade. Run from inside shadowci repo."""
import base64, gzip, json, sys
from pathlib import Path
GREEN="\033[92m"; RESET="\033[0m"; BOLD="\033[1m"
if not Path("shadowci/engine.py").exists():
    print("Run from inside your shadowci repo"); sys.exit(1)
print(f"\n{BOLD}ShadowCI v2.0.0 Upgrade{RESET}\n")
DATA = ""
files = json.loads(gzip.decompress(base64.b64decode(DATA)).decode())
for rel, content in files.items():
    p = Path(rel)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(content)
    print(f"  {GREEN}[OK]{RESET}   {rel}")
print(f"\n{BOLD}Done.{RESET}")
print("  git add -A")
print("  git commit --no-gpg-sign -m \"feat: ShadowCI v2.0.0 — 60 secret patterns, SAST, supply chain\"")
print("  git push\n")
